sql:
SELECT MAX(gdp_growth_rate)
  FROM economic_data
 WHERE year = 2000 AND quarter = 1;

SELECT AVG(gdp_growth_rate) AS avg_gdp_growth_rate
FROM economic_data
WHERE year = 2000;

